    formData.append('skillReadme', skillReadme.trim())
    try { setIsSubmitting(true); await publishSkill(formData); alert('发布成功! 请等待管理员审核。'); onSuccess() }
    catch (err) { alert('发布失败: ' + (err as Error).message) }
    finally { setIsSubmitting(false) }
