async function parseZip(file: File) {
  try {
    const { ZipReader, BlobReader, TextWriter } = await import('@zip.js/zip.js')
    const reader = new ZipReader(new BlobReader(file))
    const entries = await reader.getEntries()
    const mdEntry = entries.find(e => e.filename.toLowerCase().endsWith('skill.md'))
    if (!mdEntry) { alert('ZIP中未找到skill.md'); return }
    const content = await (mdEntry as any).getData(new TextWriter())
    await reader.close()

    // 解析 skill.md
    const lines = content.split('\n')
    let name = ''
    let desc = ''

    if (lines[0]?.trim() === '---') {
      const endIdx = lines.findIndex((l, i) => i > 0 && l.trim() === '---')
      if (endIdx > 0) {
        for (let i = 1; i < endIdx; i++) {
          const line = lines[i]
          if (line.startsWith('name:')) name = line.split(':')[1]?.trim() || ''
          if (line.startsWith('description:')) desc = line.split(':').slice(1).join(':').trim() || ''
        }
      }
    } else {
      name = lines[0]?.replace(/^#+/, '').trim() || ''
      desc = lines.slice(1).join('\n').trim()
    }

    setSkillName(name)
    setSkillDesc(desc)
  } catch (err) {
    console.error('解析ZIP失败:', err)
  }
}

